easy.solution:
def is_palindrome(text):
    cleaned = ''.join(c.lower() for c in text if c.isalnum())
    return cleaned == cleaned[::-1]

medium.solution:
def compress_string(s):
    if not s: return s
    res = []
    count = 1
    for i in range(1, len(s)):
        if s[i] == s[i-1]:
            count += 1
        else:
            res.append(s[i-1] + str(count))
            count = 1
    res.append(s[-1] + str(count))
    out = ''.join(res)
    return out if len(out) < len(s) else s

hard.solution:
def validate_password(pwd):
    issues = []
    if len(pwd) < 8:
        issues.append('Must be at least 8 characters long')
    if not any(c.isupper() for c in pwd):
        issues.append('Must contain an uppercase letter')
    if not any(c.islower() for c in pwd):
        issues.append('Must contain a lowercase letter')
    if not any(c.isdigit() for c in pwd):
        issues.append('Must contain a digit')
    specials = set('!@#$%^&*')
    if not any(c in specials for c in pwd):
        issues.append('Must contain a special character (!@#$%^&*)')
    return (len(issues) == 0, issues)

